const body = $json || {};
const ev = body.event || body.body?.event || body.body || body;
const pulseId = ev.pulseId || ev.itemId || body.pulseId || body.itemId;
const boardId = ev.boardId || body.boardId;

if (!pulseId) {
  return [{ json: { _statusCode: 400, _skip: true, ok: false, decisao: 'erro', motivo: 'payload_sem_pulseId' } }];
}

return [{ json: { pulseId: Number(pulseId), boardId: boardId ? Number(boardId) : null, _skip: false } }];

const vars = typeof $vars !== 'undefined' ? $vars : {};
const COL_CPF = vars.NEXTI_ATESTADO_COL_CPF || 'text_mm3j4nt3';
const COL_DATA_INICIO = vars.NEXTI_ATESTADO_COL_DATA_INICIO || 'date';
const COL_DATA_FIM = vars.NEXTI_ATESTADO_COL_DATA_FIM || '';
const COL_DIAS = vars.NEXTI_ATESTADO_COL_DIAS || 'numberjox5johv';
const BUFFER_DIAS = Number(vars.NEXTI_ATESTADO_BUFFER_DIAS ?? 2);

function onlyDigits(s) { return String(s || '').replace(/\D+/g, ''); }
function isTodo(v) { return !v || String(v).startsWith('TODO_'); }
function fail(status, motivo, extra = {}) {
  return [{ json: { _statusCode: status, _skip: true, ok: false, decisao: 'erro', motivo, ...extra } }];
}
function parseDataIso(text, value) {
  if (text && /^\d{4}-\d{2}-\d{2}/.test(text)) return text.slice(0, 10);
  if (value) {
    try {
      const v = typeof value === 'string' ? JSON.parse(value) : value;
      if (v && v.date) return String(v.date).slice(0, 10);
    } catch {}
  }
  return null;
}
function toDdMmYyyy000000(iso, deltaDias) {
  if (!iso) return null;
  const [y, m, d] = iso.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d));
  dt.setUTCDate(dt.getUTCDate() + (deltaDias || 0));
  const dd = String(dt.getUTCDate()).padStart(2, '0');
  const mm = String(dt.getUTCMonth() + 1).padStart(2, '0');
  return dd + mm + String(dt.getUTCFullYear()) + '000000';
}
function addDaysIso(iso, days) {
  if (!iso) return null;
  const [y, m, d] = iso.split('-').map(Number);
  const dt = new Date(Date.UTC(y, m - 1, d));
  dt.setUTCDate(dt.getUTCDate() + days);
  return dt.toISOString().slice(0, 10);
}
function numberFromText(v) {
  const n = Number(String(v || '').replace(',', '.').replace(/[^0-9.-]/g, ''));
  return Number.isFinite(n) ? n : 0;
}

const resp = $json && $json.data ? $json : ($json.body || {});
if (Array.isArray(resp.errors) && resp.errors.length) {
  return fail(502, 'erro_monday_graphql', { errors: resp.errors });
}
const item = resp?.data?.items?.[0];
if (!item) return fail(404, 'item_monday_nao_encontrado');

const missing = [];
if (isTodo(COL_CPF)) missing.push('NEXTI_ATESTADO_COL_CPF');
if (isTodo(COL_DATA_INICIO)) missing.push('NEXTI_ATESTADO_COL_DATA_INICIO');
if (isTodo(COL_DATA_FIM) && isTodo(COL_DIAS)) missing.push('NEXTI_ATESTADO_COL_DATA_FIM ou NEXTI_ATESTADO_COL_DIAS');
if (missing.length) {
  return fail(500, 'config_column_ids_ausente', {
    item_id: item.id,
    item_nome: item.name,
    missing_config: missing,
    colunas_disponiveis: (item.column_values || []).map((c) => ({ id: c.id, text: c.text })),
  });
}

const cols = (item.column_values || []).reduce((acc, c) => {
  acc[c.id] = c;
  return acc;
}, {});
const cpf = onlyDigits(cols[COL_CPF]?.text);
const dataInicioIso = parseDataIso(cols[COL_DATA_INICIO]?.text, cols[COL_DATA_INICIO]?.value);
const diasAtestado = Math.max(1, Math.ceil(numberFromText(cols[COL_DIAS]?.text || cols[COL_DIAS]?.value) || 1));
const dataFimPorDias = dataInicioIso ? addDaysIso(dataInicioIso, diasAtestado - 1) : null;
const dataFimIso = parseDataIso(cols[COL_DATA_FIM]?.text, cols[COL_DATA_FIM]?.value) || dataFimPorDias || dataInicioIso;

if (!cpf || cpf.length !== 11) {
  return fail(200, 'cpf_ausente_ou_invalido', { item_id: item.id, item_nome: item.name });
}
if (!dataInicioIso) {
  return fail(200, 'data_inicio_ausente', { item_id: item.id, item_nome: item.name, cpf });
}

return [{
  json: {
    _skip: false,
    item_id: item.id,
    item_nome: item.name,
    cpf,
    data_inicio_iso: dataInicioIso,
    data_fim_iso: dataFimIso,
    dias_atestado: diasAtestado,
    start: toDdMmYyyy000000(dataInicioIso, -BUFFER_DIAS),
    finish: toDdMmYyyy000000(dataFimIso, +BUFFER_DIAS),
  },
}];

const prev = $('Extrair CPF + datas').first().json;
const raw = $json?.body !== undefined ? $json.body : $json;
const pessoas = Array.isArray(raw) ? raw : (Array.isArray(raw?.data) ? raw.data : null);

if (!Array.isArray(pessoas)) {
  return [{ json: { _statusCode: 502, _skip: true, ok: false, decisao: 'erro', motivo: 'nexti_pessoas_resposta_invalida', cpf: prev.cpf, item_id: prev.item_id, item_nome: prev.item_nome, nexti_response: raw } }];
}
if (!pessoas.length) {
  return [{ json: { _statusCode: 200, _skip: true, ok: true, decisao: 'sem_dados_nexti', motivo: 'cpf_nao_cadastrado_no_nexti', cpf: prev.cpf, item_id: prev.item_id, item_nome: prev.item_nome } }];
}

const pessoa = pessoas.find((p) => p && p.personSituationId !== 3) || pessoas[0];
if (pessoa?.personSituationId === 3) {
  return [{ json: { _statusCode: 200, _skip: true, ok: true, decisao: 'revisar_manual', motivo: 'pessoa_demitida_no_nexti', cpf: prev.cpf, item_id: prev.item_id, item_nome: prev.item_nome, personId: pessoa.id, nome_nexti: pessoa.name || '', person_situation_id: pessoa.personSituationId, absences_encontradas: [] } }];
}

return [{ json: { _skip: false, cpf: prev.cpf, item_id: prev.item_id, item_nome: prev.item_nome, data_inicio_iso: prev.data_inicio_iso, data_fim_iso: prev.data_fim_iso, start: prev.start, finish: prev.finish, personId: pessoa.id, nome_nexti: pessoa.name || '', person_situation_id: pessoa.personSituationId } }];

const prev = $('Pick pessoa').first().json;
const raw = $json?.body !== undefined ? $json.body : $json;
const content = Array.isArray(raw?.content) ? raw.content : null;

function ddmmyyyyToIso(s) {
  if (!s || typeof s !== 'string' || s.length < 8) return null;
  return s.slice(4, 8) + '-' + s.slice(2, 4) + '-' + s.slice(0, 2);
}
if (!Array.isArray(content)) {
  return [{ json: { _statusCode: 502, _skip: true, ok: false, decisao: 'erro', motivo: 'nexti_absences_resposta_invalida', cpf: prev.cpf, item_id: prev.item_id, item_nome: prev.item_nome, personId: prev.personId, nome_nexti: prev.nome_nexti, absences_encontradas: [], nexti_response: raw } }];
}

const di = prev.data_inicio_iso;
const df = prev.data_fim_iso;
const relevantes = content.filter((a) => {
  if (!a || a.removed === true) return false;
  const aStart = ddmmyyyyToIso(a.startDateTime) || di;
  const aEnd = ddmmyyyyToIso(a.finishDateTime) || aStart;
  return aStart <= df && aEnd >= di;
});

if (!relevantes.length) {
  return [{ json: { _statusCode: 200, _skip: true, _final: true, ok: true, decisao: 'com_desconto', motivo: 'sem_ausencia_no_ponto_nexti', cpf: prev.cpf, item_id: prev.item_id, item_nome: prev.item_nome, personId: prev.personId, nome_nexti: prev.nome_nexti, absences_encontradas: [] } }];
}

return relevantes.map((a) => ({
  json: {
    _skip: false,
    _ctx: { cpf: prev.cpf, item_id: prev.item_id, item_nome: prev.item_nome, personId: prev.personId, nome_nexti: prev.nome_nexti, data_inicio_iso: di, data_fim_iso: df },
    absenceId: a.id,
    absenceSituationId: a.absenceSituationId,
    startDateTime: a.startDateTime,
    finishDateTime: a.finishDateTime,
    cidCode: a.cidCode || null,
    note: a.note || '',
  },
}));

const situationItems = $input.all();
const absenceItems = $('Filtrar absences').all();
if (!situationItems.length) {
  return [{ json: { _statusCode: 500, ok: false, decisao: 'erro', motivo: 'sem_situations_processadas' } }];
}
const ctx = absenceItems[0]?.json?._ctx || {};

function ddmmyyyyToIso(s) {
  if (!s || typeof s !== 'string' || s.length < 8) return null;
  return s.slice(4, 8) + '-' + s.slice(2, 4) + '-' + s.slice(0, 2);
}
function addDays(iso, days) {
  const d = new Date(iso + 'T00:00:00Z');
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString().slice(0, 10);
}
function coversPeriod(intervals, start, end) {
  const ordered = intervals
    .filter((i) => i.start && i.finish)
    .sort((a, b) => a.start.localeCompare(b.start));
  let cursor = start;
  for (const i of ordered) {
    if (i.finish < cursor) continue;
    if (i.start > cursor) return false;
    if (i.finish >= end) return true;
    cursor = addDays(i.finish, 1);
  }
  return false;
}

const encontradas = situationItems.map((it, index) => {
  const source = absenceItems[index]?.json || {};
  const respRaw = it.json?.body !== undefined ? it.json.body : it.json;
  const sit = respRaw?.value || respRaw || {};
  const absenceTypeId = Number(sit.absenceTypeId || 0) || null;
  return {
    absenceId: source.absenceId,
    absenceSituationId: source.absenceSituationId,
    start: source.startDateTime,
    finish: source.finishDateTime,
    start_iso: ddmmyyyyToIso(source.startDateTime),
    finish_iso: ddmmyyyyToIso(source.finishDateTime) || ddmmyyyyToIso(source.startDateTime),
    cidCode: source.cidCode || null,
    situationName: sit.name || null,
    initials: sit.initials || null,
    absenceTypeId,
  };
});

const temDemissao = encontradas.some((e) => e.absenceTypeId === 3);
const justificadas = encontradas.filter((e) => e.absenceTypeId === 1).map((e) => ({ start: e.start_iso, finish: e.finish_iso }));
const coberturaJustificada = coversPeriod(justificadas, ctx.data_inicio_iso, ctx.data_fim_iso);
const temJustificadaParcial = justificadas.length > 0 && !coberturaJustificada;
const todasNaoJustificadas = encontradas.length > 0 && encontradas.every((e) => e.absenceTypeId === 2);

let decisao = 'revisar_manual';
let motivo = 'inconsistencia_tipos_ausencia';
if (temDemissao) {
  decisao = 'revisar_manual';
  motivo = 'demissao_no_periodo';
} else if (coberturaJustificada) {
  decisao = 'sem_desconto';
  motivo = 'ausencia_justificada_cobre_periodo_no_ponto_nexti';
} else if (todasNaoJustificadas) {
  decisao = 'com_desconto';
  motivo = 'ausencia_nao_justificada_no_ponto_nexti';
} else if (temJustificadaParcial) {
  decisao = 'revisar_manual';
  motivo = 'ausencia_justificada_parcial_no_ponto_nexti';
}

return [{
  json: {
    _statusCode: 200,
    _final: true,
    ok: true,
    cpf: ctx.cpf,
    item_id: ctx.item_id,
    item_nome: ctx.item_nome,
    personId: ctx.personId,
    nome_nexti: ctx.nome_nexti,
    decisao,
    motivo,
    absences_encontradas: encontradas,
  },
}];
